// 4 parallel square computations

exercises.expected_solution:
import java.util.*;
import java.util.concurrent.*;
public class App {
    public static void main(String[] args) throws Exception {
        ExecutorService pool = Executors.newFixedThreadPool(4);
        List<Future<Integer>> futures = new ArrayList<>();
        for (int i = 1; i <= 4; i++) {
            final int n = i;
            futures.add(pool.submit(() -> n * n));
        }
        List<Integer> results = new ArrayList<>();
        for (Future<Integer> f : futures) results.add(f.get());
        System.out.println("Squares: " + results);
        System.out.println("Total: " + results.stream().mapToInt(x -> x).sum());
        pool.shutdown();
    }
}

import java.util.concurrent.*;
public class App {
    public static void main(String[] args) {
        ExecutorService pool = Executors.newSingleThreadExecutor();
        Future<Integer> future = pool.submit(() -> 10 / 0);
        try {
            System.out.println(future.get());
        } catch (ExecutionException e) {
            System.out.println("Task failed: " + e.getCause().getMessage());
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        } finally {
            pool.shutdown();
        }
    }
}

