// invokeAll for parallel factorial computation

exercises.expected_solution:
import java.util.*;
import java.util.concurrent.*;
public class App {
    static int factorial(int n) { int r=1; for (int i=2;i<=n;i++) r*=i; return r; }
    public static void main(String[] args) throws Exception {
        ExecutorService pool = Executors.newFixedThreadPool(5);
        List<Callable<String>> tasks = new ArrayList<>();
        for (int i = 1; i <= 5; i++) {
            final int n = i;
            tasks.add(() -> n + "! = " + factorial(n));
        }
        List<Future<String>> futures = pool.invokeAll(tasks);
        for (Future<String> f : futures) System.out.println(f.get());
        pool.shutdown();
    }
}

