        List<Callable<String>> tasks = Arrays.asList(
            () -> { Thread.sleep(800); return "800ms responded first"; },
            () -> { Thread.sleep(200); return "200ms responded first"; },
            () -> { Thread.sleep(500); return "500ms responded first"; }
