// Parallel stock fetch with 3-thread pool

exercises.expected_solution:
import java.util.*;
import java.util.concurrent.*;
import java.util.stream.*;
record Stock(String name, int price) {}
public class App {
    static Callable<Stock> fetchStock(String name, int price) {
        return () -> {
            Thread.sleep(100 + (int)(Math.random() * 200));
            return new Stock(name, price);
        };
    }
    public static void main(String[] args) throws Exception {
        ExecutorService pool = Executors.newFixedThreadPool(3);
        List<Callable<Stock>> tasks = Arrays.asList(
            fetchStock("TCS",     3890), fetchStock("RELIANCE", 2450),
            fetchStock("INFY",    1560), fetchStock("HDFC",     1678),
            fetchStock("WIPRO",    412), fetchStock("ZOMATO",    184)
        );
        List<Stock> stocks = pool.invokeAll(tasks).stream()
            .map(f -> { try { return f.get(); } catch (Exception e) { return null; } })
            .filter(Objects::nonNull)
            .sorted((a,b) -> Integer.compare(b.price(), a.price()))
            .collect(Collectors.toList());
        stocks.forEach(s -> System.out.printf("%s: ₹%d%n", s.name(), s.price()));
        pool.shutdown();
    }
}

