import java.util.concurrent.*;
// Parallel order validation — all must pass

exercises.expected_solution:
import java.util.*;
import java.util.concurrent.*;
public class App {
    static Callable<String> checkStock()   { return () -> { Thread.sleep(150); return "OK"; }; }
    static Callable<String> checkPayment() { return () -> { Thread.sleep(200); return "OK"; }; }
    static Callable<String> checkAddress() { return () -> { Thread.sleep(100); return "OK"; }; }

    public static void main(String[] args) throws InterruptedException {
        ExecutorService pool = Executors.newFixedThreadPool(3);

        List<Callable<String>> checks = Arrays.asList(
            checkStock(), checkPayment(), checkAddress());
        String[] names = {"Stock", "Payment", "Address"};

        List<Future<String>> futures = pool.invokeAll(checks);

        boolean passed = true;
        for (int i = 0; i < futures.size(); i++) {
            try {
                String result = futures.get(i).get();
                System.out.println(names[i] + ": " + result);
            } catch (ExecutionException e) {
                System.out.println(names[i] + ": FAILED — " + e.getCause().getMessage());
                passed = false;
            }
        }
        System.out.println(passed ? "Order accepted!" : "Order rejected.");
        pool.shutdown();
    }
}

