import java.util.*;
import java.util.concurrent.*;
import java.util.stream.*;
// Batch processing with thread pool

exercises.expected_solution:
import java.util.*;
import java.util.concurrent.*;
import java.util.stream.*;
public class App {
    public static void main(String[] args) throws Exception {
        List<Integer> data = IntStream.rangeClosed(1, 20).boxed().collect(Collectors.toList());
        int batchSize = 5;
        ExecutorService pool = Executors.newFixedThreadPool(4);

        List<Future<List<Integer>>> futures = new ArrayList<>();
        for (int i = 0; i < data.size(); i += batchSize) {
            List<Integer> batch = data.subList(i, Math.min(i + batchSize, data.size()));
            futures.add(pool.submit(() ->
                batch.stream().map(n -> n * n).collect(Collectors.toList())));
        }

        int batchNum = 1;
        int total = 0;
        for (Future<List<Integer>> f : futures) {
            List<Integer> result = f.get();
            System.out.println("Batch " + batchNum++ + ": " + result);
            total += result.size();
        }
        System.out.println("Total processed: " + total);
        pool.shutdown();
    }
}

