// Async payment processor with timeout and fallback

exercises.expected_solution:
import java.util.*;
import java.util.concurrent.*;
public class App {
    static final Random rnd = new Random(42);

    static Callable<String> processPayment(String id, int amount) {
        return () -> {
            Thread.sleep(50);  // validation
            if (rnd.nextDouble() < 0.2) throw new RuntimeException("card declined");
            Thread.sleep(100 + rnd.nextInt(200));  // processing
            return "SUCCESS ₹" + amount;
        };
    }

    public static void main(String[] args) throws InterruptedException {
        ExecutorService pool = Executors.newFixedThreadPool(3);
        int[] amounts = {1500, 800, 2200, 500, 3000};
        String[] ids   = {"PAY-001", "PAY-002", "PAY-003", "PAY-004", "PAY-005"};

        List<Future<String>> futures = new ArrayList<>();
        for (int i = 0; i < ids.length; i++)
            futures.add(pool.submit(processPayment(ids[i], amounts[i])));

        int succeeded = 0, failed = 0, timedOut = 0;
        for (int i = 0; i < futures.size(); i++) {
            Future<String> f = futures.get(i);
            try {
                String result = f.get(400, TimeUnit.MILLISECONDS);
                System.out.println(ids[i] + ": " + result);
                succeeded++;
            } catch (TimeoutException e) {
                System.out.println(ids[i] + ": TIMEOUT");
                f.cancel(true);
                timedOut++;
            } catch (ExecutionException e) {
                System.out.println(ids[i] + ": FAILED " + e.getCause().getMessage());
                failed++;
            }
        }
        System.out.printf("Summary: %d succeeded, %d failed, %d timed out%n",
            succeeded, failed, timedOut);
        pool.shutdownNow();
    }
}
